'use client';

import { useEffect, useState, useRef, useCallback } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import Link from 'next/link';
import {
    LayoutDashboard,
    Package,
    ShoppingBag,
    MessageSquare,
    Users,
    LogOut,
    Menu,
    X,
    Bell,
    ShoppingCart,
    Mail,
    Rss,
    ChevronRight,
    Ticket,
} from 'lucide-react';
import { supabase } from '@/lib/supabase';

// ─── Types ─────────────────────────────────────────────────────────────────────
interface Notif {
    id: string;
    type: 'order' | 'query' | 'subscriber' | 'user';
    title: string;
    description: string;
    href: string;
    time: Date;
}

const ICONS  = { order: ShoppingCart, query: Mail, subscriber: Rss, user: Users };
const COLORS  = { order: 'bg-blue-500', query: 'bg-violet-500', subscriber: 'bg-emerald-500', user: 'bg-amber-500' };
const HREFS   = { order: '/admin/orders', query: '/admin/queries', subscriber: '/admin/subscribers', user: '/admin/users' };

// ─── Toast (solo visual, se auto-cierra pero NO borra el historial) ─────────────
function NotifToast({ notif, onDismiss }: { notif: Notif; onDismiss: () => void }) {
    const Icon = ICONS[notif.type];
    useEffect(() => {
        const t = setTimeout(onDismiss, 6000);
        return () => clearTimeout(t);
    }, [onDismiss]);

    return (
        <Link
            href={notif.href}
            onClick={onDismiss}
            className="flex items-start gap-3 bg-white rounded-2xl shadow-xl border border-stone-100 p-4 w-80 animate-in slide-in-from-right-4 fade-in duration-300 hover:border-stone-300 transition-colors group"
        >
            <div className={`${COLORS[notif.type]} rounded-xl p-2 flex-shrink-0`}>
                <Icon size={18} className="text-white" />
            </div>
            <div className="flex-1 min-w-0">
                <p className="text-sm font-bold text-stone-900">{notif.title}</p>
                <p className="text-xs text-stone-500 truncate">{notif.description}</p>
                <p className="text-[10px] text-primary mt-0.5 flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
                    Ver ahora <ChevronRight size={10} />
                </p>
            </div>
            <button onClick={(e) => { e.preventDefault(); onDismiss(); }} className="text-stone-300 hover:text-stone-500 flex-shrink-0 mt-0.5">
                <X size={14} />
            </button>
        </Link>
    );
}

// ─── Admin Layout ───────────────────────────────────────────────────────────────
export default function AdminLayout({ children }: { children: React.ReactNode }) {
    const [isAuthorized, setIsAuthorized] = useState(false);
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);

    // history = persistido en localStorage para que sobreviva refrescos
    const [history, setHistory]   = useState<Notif[]>([]);
    const [toasts, setToasts]     = useState<Notif[]>([]);
    const [showBell, setShowBell] = useState(false);

    const router   = useRouter();
    const pathname = usePathname();
    const seenIds  = useRef<Set<string>>(new Set());
    const bellRef  = useRef<HTMLButtonElement>(null);
    const dropdownRef = useRef<HTMLDivElement>(null);

    useEffect(() => { setIsAuthorized(true); }, []);

    // Cargar historial desde localStorage al montar
    useEffect(() => {
        try {
            const saved = localStorage.getItem('wayku_admin_notifs');
            if (saved) {
                const parsed = JSON.parse(saved) as Notif[];
                // Convertir strings de fecha de vuelta a Date
                setHistory(parsed.map(n => ({ ...n, time: new Date(n.time) })));
            }
        } catch (e) {}
    }, []);

    // Cerrar dropdown al click afuera (excluyendo el botón Y el propio dropdown)
    useEffect(() => {
        const handler = (e: MouseEvent) => {
            const t = e.target as Node;
            const outsideBell     = bellRef.current     && !bellRef.current.contains(t);
            const outsideDropdown = dropdownRef.current && !dropdownRef.current.contains(t);
            if (outsideBell && outsideDropdown) setShowBell(false);
        };
        document.addEventListener('mousedown', handler);
        return () => document.removeEventListener('mousedown', handler);
    }, []);

    const addNotif = useCallback((notif: Omit<Notif, 'id' | 'time'>) => {
        const id = Math.random().toString(36).slice(2);
        const full: Notif = { ...notif, id, time: new Date() };
        setHistory(prev => {
            const next = [full, ...prev].slice(0, 50); // máximo 50
            try { localStorage.setItem('wayku_admin_notifs', JSON.stringify(next)); } catch (e) {}
            return next;
        });
        setToasts(prev => [...prev, full]);
    }, []);

    const dismissToast = useCallback((id: string) => {
        setToasts(prev => prev.filter(n => n.id !== id));
        // NO borramos de history
    }, []);

    const clearHistory = useCallback(() => {
        setHistory([]);
        try { localStorage.removeItem('wayku_admin_notifs'); } catch (e) {}
        setShowBell(false);
    }, []);

    const unread = history.length;

    // ─ Supabase Realtime ────────────────────────────────────────────────────────
    useEffect(() => {
        if (!supabase || pathname === '/admin/login') return;

        const channel = supabase
            .channel('admin-live')
            .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'orders' }, (payload) => {
                const row = payload.new as any;
                if (seenIds.current.has(`order-${row.id}`)) return;
                seenIds.current.add(`order-${row.id}`);
                addNotif({ type: 'order', title: '🛒 Nuevo Pedido', description: `${row.customer || row.email || 'Cliente'} — $${Number(row.total || 0).toLocaleString()}`, href: HREFS.order });
            })
            .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'queries' }, (payload) => {
                const row = payload.new as any;
                if (seenIds.current.has(`query-${row.id}`)) return;
                seenIds.current.add(`query-${row.id}`);
                addNotif({ type: 'query', title: '✉️ Nueva Consulta', description: `${row.name || 'Visitante'}: ${row.subject || ''}`, href: HREFS.query });
            })
            .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'subscribers' }, (payload) => {
                const row = payload.new as any;
                if (seenIds.current.has(`sub-${row.id || row.email}`)) return;
                seenIds.current.add(`sub-${row.id || row.email}`);
                addNotif({ type: 'subscriber', title: '📬 Nueva Suscripción', description: row.email || 'Email desconocido', href: HREFS.subscriber });
            })
            .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'users' }, (payload) => {
                const row = payload.new as any;
                if (seenIds.current.has(`user-${row.id}`)) return;
                seenIds.current.add(`user-${row.id}`);
                addNotif({ type: 'user', title: '👤 Nuevo Usuario', description: `${row.full_name || row.name || 'Sin nombre'} — ${row.email || ''}`, href: HREFS.user });
            })
            .subscribe();

        return () => { supabase?.removeChannel(channel); };
    }, [addNotif, pathname]);

    const handleLogout = async () => {
        await fetch('/api/admin/auth', { method: 'DELETE' });
        router.push('/admin/login');
        router.refresh();
    };

    if (pathname === '/admin/login') return <>{children}</>;
    if (!isAuthorized) return null;

    const navigation = [
        { name: 'Dashboard',     href: '/admin/dashboard',   icon: LayoutDashboard },
        { name: 'Productos',     href: '/admin/products',    icon: Package },
        { name: 'Cupones',       href: '/admin/coupons',     icon: Ticket },
        { name: 'Pedidos',       href: '/admin/orders',      icon: ShoppingBag },
        { name: 'Consultas',     href: '/admin/queries',     icon: MessageSquare },
        { name: 'Suscripciones', href: '/admin/subscribers', icon: Users },
        { name: 'Usuarios',      href: '/admin/users',       icon: Users },
    ];

    return (
        <div className="min-h-screen bg-stone-50 flex">
            {isSidebarOpen && (
                <div className="fixed inset-0 z-40 bg-stone-900/50 backdrop-blur-sm lg:hidden" onClick={() => setIsSidebarOpen(false)} />
            )}

            {/* Sidebar */}
            <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-stone-900 text-white transition-transform duration-300 ease-in-out lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
                <div className="flex flex-col h-full">
                    {/* Header del sidebar */}
                    <div className="h-16 flex items-center justify-between px-5 border-b border-stone-800">
                        <span className="font-serif text-base tracking-wider uppercase whitespace-nowrap">Waykú Admin</span>

                        {/* Bell button — position:relative aquí */}
                        <button
                            ref={bellRef}
                            onClick={() => setShowBell(v => !v)}
                            className="relative p-1.5 text-stone-400 hover:text-white transition-colors rounded-lg hover:bg-stone-800"
                        >
                            <Bell size={17} />
                            {unread > 0 && (
                                <span className="absolute -top-1 -right-1 h-4 w-4 flex items-center justify-center rounded-full bg-primary text-[9px] font-bold text-white">
                                    {unread > 9 ? '9+' : unread}
                                </span>
                            )}
                        </button>
                    </div>

                    <nav className="flex-1 px-4 py-6 space-y-1">
                        {navigation.map((item) => {
                            const isActive = pathname === item.href;
                            return (
                                <Link
                                    key={item.name}
                                    href={item.href}
                                    onClick={() => setIsSidebarOpen(false)}
                                    className={`flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${isActive ? 'bg-primary text-white' : 'text-stone-400 hover:text-white hover:bg-stone-800'}`}
                                >
                                    <item.icon size={20} />
                                    {item.name}
                                </Link>
                            );
                        })}
                    </nav>

                    <div className="p-4 border-t border-stone-800">
                        <button onClick={handleLogout} className="flex items-center gap-3 w-full px-3 py-2 text-stone-400 hover:text-white hover:bg-stone-800 rounded-lg text-sm font-medium transition-colors">
                            <LogOut size={20} />
                            Cerrar Sesión
                        </button>
                    </div>
                </div>
            </aside>

            {/* Main */}
            <div className="flex-1 flex flex-col lg:pl-64">
                <header className="h-16 bg-white border-b border-stone-100 flex items-center justify-between px-4 lg:hidden">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-stone-600 hover:bg-stone-100 rounded-lg">
                        {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
                    </button>
                    <span className="font-serif text-xl tracking-widest uppercase">Waykú</span>
                    <div className="w-10" />
                </header>
                <main className="p-4 sm:p-6 lg:p-8">{children}</main>
            </div>

            {/* ── Bell dropdown — fixed, fuera del sidebar ── */}
            {showBell && (
                <div
                    ref={dropdownRef}
                    className="fixed top-4 left-[148px] z-[200] w-80 bg-stone-800 border border-stone-700 rounded-2xl shadow-2xl overflow-hidden"
                >
                    <div className="flex items-center justify-between px-4 py-3 border-b border-stone-700">
                        <span className="text-xs font-bold text-stone-300 uppercase tracking-widest">Notificaciones</span>
                        {history.length > 0 && (
                            <button onClick={clearHistory} className="text-[10px] text-stone-400 hover:text-white transition-colors">
                                Limpiar todo
                            </button>
                        )}
                    </div>
                    {history.length === 0 ? (
                        <p className="text-xs text-stone-400 text-center py-5">Sin notificaciones nuevas</p>
                    ) : (
                        <div className="max-h-72 overflow-y-auto divide-y divide-stone-700/50">
                            {history.map(n => {
                                const Icon = ICONS[n.type];
                                return (
                                    <Link key={n.id} href={n.href} onClick={() => setShowBell(false)}
                                        className="flex items-start gap-3 px-4 py-3 hover:bg-stone-700/50 transition-colors">
                                        <div className={`${COLORS[n.type]} rounded-lg p-1.5 flex-shrink-0 mt-0.5`}>
                                            <Icon size={12} className="text-white" />
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <p className="text-xs font-semibold text-white">{n.title}</p>
                                            <p className="text-[10px] text-stone-400 truncate">{n.description}</p>
                                        </div>
                                        <ChevronRight size={12} className="text-stone-500 flex-shrink-0 mt-1" />
                                    </Link>
                                );
                            })}
                        </div>
                    )}
                </div>
            )}

            {/* ── Toasts — fixed bottom-right, se auto-cierran pero no borran historial ── */}
            <div className="fixed bottom-6 right-6 z-[100] flex flex-col gap-3 pointer-events-none">
                {toasts.slice(-4).map(n => (
                    <div key={n.id} className="pointer-events-auto">
                        <NotifToast notif={n} onDismiss={() => dismissToast(n.id)} />
                    </div>
                ))}
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/Button';
import { Lock, User } from 'lucide-react';

export default function AdminLoginPage() {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const router = useRouter();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setIsLoading(true);

        try {
            const res = await fetch('/api/admin/auth', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ username, password })
            });
            const data = await res.json();
            
            if (res.ok && data.success) {
                router.push('/admin/dashboard');
                router.refresh();
            } else {
                setError(data.error || 'Usuario o contraseña incorrectos');
                setIsLoading(false);
            }
        } catch (e) {
            setError('Error de conexión');
            setIsLoading(false);
        }
    };

    return (
        <div className="flex min-h-screen items-center justify-center bg-stone-50 px-4">
            <div className="w-full max-w-md">
                <div className="text-center mb-8">
                    <h1 className="font-serif text-4xl tracking-widest text-stone-800 uppercase mb-2">
                        Waykú
                    </h1>
                    <p className="text-stone-500">Panel de Administración</p>
                </div>

                <div className="bg-white p-8 rounded-2xl shadow-sm border border-stone-100">
                    <form onSubmit={handleLogin} className="space-y-6">
                        <div>
                            <label className="block text-sm font-medium text-stone-700 mb-2">
                                Usuario
                            </label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-stone-400">
                                    <User size={18} />
                                </div>
                                <input
                                    type="text"
                                    value={username}
                                    onChange={(e) => setUsername(e.target.value)}
                                    className="block w-full pl-10 pr-3 py-2 border border-stone-300 rounded-lg focus:ring-primary focus:border-primary sm:text-sm"
                                    placeholder="Usuario"
                                    required
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-stone-700 mb-2">
                                Contraseña
                            </label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-stone-400">
                                    <Lock size={18} />
                                </div>
                                <input
                                    type="password"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="block w-full pl-10 pr-3 py-2 border border-stone-300 rounded-lg focus:ring-primary focus:border-primary sm:text-sm"
                                    placeholder="••••••••"
                                    required
                                />
                            </div>
                        </div>

                        {error && (
                            <p className="text-red-500 text-sm text-center font-medium">
                                {error}
                            </p>
                        )}

                        <Button
                            type="submit"
                            className="w-full"
                            disabled={isLoading}
                        >
                            {isLoading ? 'Ingresando...' : 'Ingresar'}
                        </Button>
                    </form>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useApp, Order } from '@/context/AppContext';
import { Button } from '@/components/ui/Button';
import {
    Search,
    Filter,
    MoreVertical,
    X,
    Package,
    CheckCircle2,
    Clock,
    Truck,
    HelpCircle,
    Printer,
    RefreshCw,
    AlertTriangle
} from 'lucide-react';
import { getTimeAgo } from '@/lib/time';

function escapeHtml(unsafe: string | null | undefined): string {
    if (!unsafe) return '';
    return unsafe.toString()
         .replace(/&/g, "&amp;")
         .replace(/</g, "&lt;")
         .replace(/>/g, "&gt;")
         .replace(/"/g, "&quot;")
         .replace(/'/g, "&#039;");
}

export default function AdminOrdersPage() {
    const { orders: contextOrders, updateOrderStatus } = useApp();
    const [orders, setOrders] = useState<Order[]>(contextOrders);
    const [isLoading, setIsLoading] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState('Todos');
    const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
    const [confirmAction, setConfirmAction] = useState<string | null>(null);

    // Keep in sync with context on mount
    useEffect(() => { setOrders(contextOrders); }, [contextOrders]);

    const fetchOrders = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await fetch('/api/admin/data');
            const data = await res.json();
            if (data.orders) setOrders(data.orders);
        } catch (e) {
            console.error('Error fetching orders:', e);
        } finally {
            setIsLoading(false);
        }
    }, []);

    // Orders sorted newest-first
    const sortedOrders = [...orders].sort((a, b) => {
        let timeA = 0; let timeB = 0;
        if (a.created_at) timeA = new Date(a.created_at).getTime();
        if (b.created_at) timeB = new Date(b.created_at).getTime();
        
        if (timeA === 0 && a.id && a.id.startsWith('ORD-') && a.id.length > 10) {
            const ts = Number(a.id.replace('ORD-', ''));
            if (!isNaN(ts) && ts > 1000000000) timeA = ts;
        }
        if (timeB === 0 && b.id && b.id.startsWith('ORD-') && b.id.length > 10) {
            const ts = Number(b.id.replace('ORD-', ''));
            if (!isNaN(ts) && ts > 1000000000) timeB = ts;
        }
        
        if (timeA !== 0 && timeB !== 0 && timeA !== timeB) {
            return timeB - timeA;
        }
        
        // Fallback to numeric ID sort
        const numA = Number(String(a.id).replace('ORD-', ''));
        const numB = Number(String(b.id).replace('ORD-', ''));
        if (!isNaN(numA) && !isNaN(numB)) {
             return numB - numA;
        }
        
        return String(b.id).localeCompare(String(a.id));
    });

    const filteredOrders = sortedOrders.filter(order => {
        const matchesSearch = order.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                              order.customer.toLowerCase().includes(searchTerm.toLowerCase()) ||
                              (order.total?.toString() || '').includes(searchTerm.toLowerCase());
        const matchesStatus = statusFilter === 'Todos' || order.status === statusFilter;
        return matchesSearch && matchesStatus;
    });

    const getStatusStyles = (status: string) => {
        switch (status) {
            case 'Entregado': return 'bg-green-100 text-green-700';
            case 'Pedido recibido': return 'bg-yellow-100 text-yellow-700 font-medium';
            case 'Pago acreditado': return 'bg-emerald-100 text-emerald-700';
            case 'En preparación': return 'bg-blue-100 text-blue-700';
            case 'Embalado': return 'bg-indigo-100 text-indigo-700';
            case 'Despachado': return 'bg-purple-100 text-purple-700';
            case 'Devolución': return 'bg-orange-100 text-orange-700';
            case 'Cancelado': return 'bg-red-100 text-red-700';
            default: return 'bg-stone-100 text-stone-700';
        }
    };

    return (
        <div className="space-y-8">
            <div className="flex items-start justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-stone-900">Pedidos</h1>
                    <p className="text-stone-500">Gestiona las ventas y el estado de los envíos.</p>
                </div>
                <button
                    onClick={fetchOrders}
                    className="flex items-center gap-2 text-sm text-stone-500 hover:text-primary transition-colors border border-stone-200 rounded-lg px-3 py-2"
                    title="Actualizar pedidos"
                >
                    <RefreshCw size={15} className={isLoading ? 'animate-spin' : ''} />
                    Actualizar
                </button>
            </div>

            {/* Filters and Search */}
            <div className="bg-white p-4 rounded-2xl shadow-sm border border-stone-100 flex flex-col sm:flex-row gap-4">
                <div className="relative flex-1">
                    <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-stone-400">
                        <Search size={18} />
                    </div>
                    <input
                        type="text"
                        placeholder="Buscar por ID, cliente o total..."
                        className="block w-full pl-10 pr-3 py-2 border border-stone-200 rounded-xl focus:ring-primary focus:border-primary sm:text-sm"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
                <select
                    value={statusFilter}
                    onChange={(e) => setStatusFilter(e.target.value)}
                    className="w-full sm:w-auto px-4 py-2 bg-stone-50 border border-stone-200 rounded-xl focus:ring-primary focus:border-primary text-sm font-medium text-stone-700"
                >
                    <option value="Todos">Todos los Estados</option>
                    <option value="Pedido recibido">Pedido recibido</option>
                    <option value="Pago acreditado">Pago acreditado</option>
                    <option value="En preparación">En preparación</option>
                    <option value="Embalado">Embalado</option>
                    <option value="Despachado">Despachado</option>
                    <option value="Entregado">Entregado</option>
                    <option value="Devolución">Devolución</option>
                    <option value="Cancelado">Cancelado</option>
                </select>
            </div>

            {/* Orders Table (Desktop) */}
            <div className="hidden lg:block bg-white rounded-2xl shadow-sm border border-stone-100 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-stone-50 text-stone-500 text-xs uppercase tracking-wider">
                            <tr>
                                <th className="px-6 py-4 font-medium">ID Pedido</th>
                                <th className="px-6 py-4 font-medium">Cliente</th>
                                <th className="px-6 py-4 font-medium">Fecha</th>
                                <th className="px-6 py-4 font-medium">Items</th>
                                <th className="px-6 py-4 font-medium">Total</th>
                                <th className="px-6 py-4 font-medium">Estado</th>
