            html: htmlTemplate,
        });

        return NextResponse.json({ success: true, sentCount: subscribers.length });
    } catch (error: any) {
        console.error('Error enviando campaña:', error);
        return NextResponse.json({ error: 'Failed to send campaign' }, { status: 500 });
