                        <dl className="mt-6 space-y-4 text-sm font-medium text-stone-500">
                            <div className="flex justify-between">
                                <dt>Subtotal</dt>
                                <dd className="text-stone-900">${subtotal.toLocaleString()}</dd>
                            </div>
                            <div className="flex justify-between">
                                        <dt>Envío</dt>
                                        <dd className="text-stone-900">
