'use client';

import { useEffect, useState, Suspense } from 'react';
import { useCart } from '@/context/CartContext';
import { useApp } from '@/context/AppContext';
import { useSearchParams } from 'next/navigation';

import { Button } from '@/components/ui/Button';
import { CheckCircle, MessageCircle } from 'lucide-react';
import Link from 'next/link';

function SuccessContent() {
    const { clearCart, items } = useCart();
    const { updateProduct, products, updateOrderStatus } = useApp();
    const [isProcessed, setIsProcessed] = useState(false);
    const searchParams = useSearchParams();

    const method = searchParams.get('method');
    const name = searchParams.get('name') || '';
    const total = searchParams.get('total') || '';
    
    // Mercado Pago params
    const status = searchParams.get('status');
    const paymentId = searchParams.get('payment_id');
    const externalReference = searchParams.get('external_reference');
    const orderIdParam = searchParams.get('order_id');

    useEffect(() => {
        const orderId = externalReference || orderIdParam;
        
        if (!isProcessed && (status === 'approved' || method === 'transfer')) {
            // Marcar pedido como pagado/procesando si viene de MercadoPago (Card)
            // Ya no dependemos de que hayan items en el cart, para soportar reloads.
            if (status === 'approved' && orderId) {
                updateOrderStatus(orderId, 'Pago acreditado');
                console.log("Order checked out successfully:", orderId);
            } else if (method === 'transfer' && orderId) {
                updateOrderStatus(orderId, 'Pedido recibido');
            }
            
            // clearCart ya se llamó en checkout/page.tsx, pero lo llamamos por las dudas
            clearCart();
            setIsProcessed(true);
        }
    }, [isProcessed, status, method, externalReference, orderIdParam, updateOrderStatus, clearCart]);

    return (
        <div className="flex min-h-[80vh] flex-col items-center justify-center px-4 py-12 text-center max-w-4xl mx-auto">
            <div className={`mx-auto flex h-20 w-20 items-center justify-center rounded-full mb-8 ${method === 'transfer' ? 'bg-amber-100 text-amber-600' : 'bg-green-100 text-green-600'}`}>
                <CheckCircle size={48} />
            </div>

            <h1 className="text-4xl font-serif text-stone-900 mb-4">
                {method === 'transfer' ? '¡Pedido recibido!' : '¡Gracias por tu compra!'}
            </h1>

            <p className="text-lg text-stone-600 max-w-md mx-auto mb-8">
                {method === 'transfer'
                    ? `Hola ${name}, hemos registrado tu pedido. Para finalizar el proceso, por favor seguí las instrucciones de pago.`
                    : 'Tu pedido ha sido procesado con éxito. Pronto recibirás un correo electrónico con los detalles de tu compra.'}
            </p>

            {method === 'transfer' && (
                <div className="bg-stone-50 border border-stone-200 rounded-3xl p-8 mb-12 text-left w-full max-w-2xl shadow-sm animate-in zoom-in-95 duration-500">
                    <h3 className="text-xl font-bold text-stone-900 mb-6 border-b border-stone-200 pb-3 font-serif">Instrucciones de Pago</h3>

                    <div className="space-y-6 mb-8">
                        <div className="flex justify-between items-center bg-white p-4 rounded-2xl border border-stone-100 shadow-sm">
                            <span className="text-stone-500 font-bold text-xs uppercase tracking-widest italic">Total a transferir</span>
                            <span className="text-primary font-bold text-2xl">${Number(total).toLocaleString()}</span>
                        </div>

                        <div className="bg-white p-6 rounded-2xl border border-stone-100 shadow-sm space-y-5">
                            <div className="flex items-center justify-between group">
                                <div className="flex flex-col">
                                    <span className="text-[10px] text-stone-400 uppercase font-bold tracking-widest">Alias</span>
                                    <span className="text-stone-900 font-bold text-lg font-mono">waykuargentina</span>
                                </div>
                                <Button 
                                    variant="outline" size="sm" className="h-8 px-4 rounded-xl border-stone-200 hover:border-primary hover:text-primary transition-all"
                                    onClick={() => {navigator.clipboard.writeText('waykuargentina'); alert('Alias copiado')}}
                                >Copiar</Button>
                            </div>

                            <div className="flex items-center justify-between group">
                                <div className="flex flex-col">
                                    <span className="text-[10px] text-stone-400 uppercase font-bold tracking-widest">CVU</span>
                                    <span className="text-stone-900 font-bold text-lg font-mono">0000003100043743912911</span>
                                </div>
                                <Button 
                                    variant="outline" size="sm" className="h-8 px-4 rounded-xl border-stone-200 hover:border-primary hover:text-primary transition-all"
                                    onClick={() => {navigator.clipboard.writeText('0000003100043743912911'); alert('CVU copiado')}}
                                >Copiar</Button>
                            </div>

                            <div className="grid grid-cols-2 gap-6 border-t border-stone-100 pt-5">
                                <div className="flex flex-col">
                                    <span className="text-[10px] text-stone-400 uppercase font-bold tracking-widest">Titular</span>
                                    <span className="text-stone-900 font-bold text-sm">Valentino Mateo Olmedo</span>
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-[10px] text-stone-400 uppercase font-bold tracking-widest">CUIT/CUIL</span>
                                    <span className="text-stone-900 font-bold text-sm">20-47304165-1</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="bg-green-50 border border-green-100 rounded-2xl p-5 flex gap-4 items-start">
                        <div className="h-10 w-10 rounded-full bg-green-100 flex items-center justify-center flex-shrink-0 text-green-600">
                            <MessageCircle size={20} />
                        </div>
                        <div>
                            <p className="font-bold text-green-900 text-sm mb-1">¡Siguiente Paso!</p>
                            <p className="text-xs text-green-700 leading-relaxed mb-1">
                                Para que despachemos tu lámpara, enviá el comprobante por WhatsApp al <strong className="text-green-900">3513844333</strong>.
                            </p>
                        </div>
                    </div>
                </div>
            )}
            <div className="flex flex-col sm:flex-row gap-4">
                {method === 'transfer' ? (
                    <a
                        href={`https://wa.me/543513844333?text=Hola,%20envio%20el%20comprobante%20de%20mi%20pedido%20a%20nombre%20de%20${encodeURIComponent(name)}`}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="w-full sm:w-auto"
                    >
                        <Button className="w-full sm:w-auto px-10 py-7 rounded-2xl text-lg bg-green-600 hover:bg-green-700 flex items-center justify-center gap-2 shadow-lg hover:shadow-green-200 transition-all font-bold">
                            <MessageCircle size={22} />
                            Enviar Comprobante
                        </Button>
                    </a>
                ) : (
                    <Link href="/products">
                        <Button className="px-8 py-6 text-lg">Seguir comprando</Button>
                    </Link>
                )}
                <Link href="/">
                    <Button variant="outline" className="px-8 py-6 text-lg">Volver al inicio</Button>
                </Link>
            </div>


        </div>
    );
}

export default function SuccessPage() {
    return (
        <Suspense fallback={<div className="min-h-screen flex items-center justify-center">Cargando...</div>}>
            <SuccessContent />
        </Suspense>
    );
}

'use client';

import { useState } from 'react';
import { useAuth } from '@/context/AuthContext';
import { Button } from '@/components/ui/Button';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { LogIn } from 'lucide-react';

export default function LoginPage() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const { login } = useAuth();
    const router = useRouter();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setIsLoading(true);

        try {
            await login(email, password);
            router.push('/');
        } catch (err: any) {
            setError(err.message || 'Error al iniciar sesión');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex min-h-[80vh] flex-col items-center justify-center px-4 py-12">
            <div className="w-full max-w-md space-y-8 bg-white p-8 rounded-2xl shadow-sm border border-stone-100">
                <div className="text-center">
                    <div className="mx-auto flex h-12 w-12 items-center justify-center rounded-full bg-primary/10 text-primary">
                        <LogIn size={24} />
                    </div>
                    <h2 className="mt-6 text-3xl font-bold tracking-tight text-stone-900">Bienvenido de nuevo</h2>
                    <p className="mt-2 text-sm text-stone-500">
                        Ingresa tus credenciales para acceder a tu cuenta
                    </p>
                </div>

                <form className="mt-8 space-y-6" onSubmit={handleSubmit}>
                    <div className="space-y-4 rounded-md shadow-sm">
                        <div>
                            <label htmlFor="email-address" className="sr-only">Correo electrónico</label>
                            <input
                                id="email-address"
                                name="email"
                                type="email"
                                autoComplete="email"
                                required
                                className="relative block w-full rounded-xl border border-stone-200 px-4 py-3 text-stone-900 placeholder-stone-400 focus:z-10 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary sm:text-sm"
                                placeholder="Correo electrónico"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                            />
                        </div>
                        <div>
                            <label htmlFor="password" className="sr-only">Contraseña</label>
                            <input
                                id="password"
                                name="password"
                                type="password"
                                autoComplete="current-password"
                                required
                                className="relative block w-full rounded-xl border border-stone-200 px-4 py-3 text-stone-900 placeholder-stone-400 focus:z-10 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary sm:text-sm"
                                placeholder="Contraseña"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                            />
                        </div>
                    </div>

                    {error && (
                        <div className="text-red-500 text-sm text-center bg-red-50 p-2 rounded-lg">
                            {error}
                        </div>
                    )}

                    <div>
                        <Button
                            type="submit"
                            className="w-full py-6 text-base font-semibold"
                            disabled={isLoading}
                        >
                            {isLoading ? 'Iniciando sesión...' : 'Iniciar Sesión'}
                        </Button>
                    </div>
                </form>

                <div className="text-center text-sm">
                    <span className="text-stone-500">¿No tienes una cuenta? </span>
                    <Link href="/register" className="font-medium text-primary hover:text-primary/80">
                        Regístrate aquí
                    </Link>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useApp } from '@/context/AppContext';
import { useParams, notFound } from 'next/navigation';
import Image from 'next/image';
import { Button } from '@/components/ui/Button';
import { Check, Truck, Shield, ArrowLeft, Star, Heart, Hammer, PlusCircle, Clock, X } from 'lucide-react';
import Link from 'next/link';
import { useCart } from '@/context/CartContext';
import { useFavorites } from '@/context/FavoritesContext';
import { useAuth } from '@/context/AuthContext';
import { useState, useEffect, useMemo } from 'react';

export default function ProductPage() {
    const params = useParams();
    const { products, reviews, addReview } = useApp();
    const { user } = useAuth();

    const decodedId = params?.id ? decodeURIComponent(params.id as string) : '';
    const product = products.find((p) => p.id === decodedId);
    
    // Default to the first ones, then we'll adjust in useEffect if needed
    const [selectedMaterial, setSelectedMaterial] = useState<'guayubira' | 'roble' | 'palo-santo'>('roble');
    const [selectedSize, setSelectedSize] = useState<'1m' | '1.5m' | '2m'>('1m');
    const [selectedImageIndex, setSelectedImageIndex] = useState(0);
    const [shadeType, setShadeType] = useState<'lino' | 'blanco-calido' | 'blanco-frio'>('lino');
    const [cableColor, setCableColor] = useState<'blanco' | 'negro'>('blanco');
    const [canopyColor, setCanopyColor] = useState<'blanco' | 'negro'>('blanco');
    const [autoSelected, setAutoSelected] = useState(false);

    const [reviewComment, setReviewComment] = useState('');
    const [reviewRating, setReviewRating] = useState(5);
    const [reviewImage, setReviewImage] = useState<string | null>(null);
    const [isUploadingImage, setIsUploadingImage] = useState(false);

    const { addItem } = useCart();
    const { toggleFavorite, isFavorite } = useFavorites();


    const similarProducts = useMemo(() => {
        if (!product) return [];
        return products
            .filter(p => p.category === product.category && p.id !== product.id && p.isVisible !== false)
            .slice(0, 3);
    }, [product, products]);

    const productReviews = useMemo(() => {
        return reviews.filter(r => r.productId === decodedId);
    }, [reviews, decodedId]);

    // Auto-select the first available variant on mount
    useEffect(() => {
        if (product?.variants && product.variants.length > 0 && !autoSelected) {
            const availableVariant = product.variants.find(v => v.stock > 0);
            if (availableVariant) {
                if (availableVariant.material) setSelectedMaterial(availableVariant.material as any);
                if (availableVariant.size) setSelectedSize(availableVariant.size as any);
            }
            setAutoSelected(true);
        }
    }, [product, autoSelected]);



    const handleAddToCart = () => {
        if (!product) return;
        
        const isUnifiedCableCanopy = product.category === 'pendant' && product.id !== 'new-1' && product.id !== 'new-4';

        addItem(
            product,
            selectedMaterial,
            hasSizeVariants ? selectedSize : undefined,
            product.category === 'table' ? shadeType : undefined,
            (product.category === 'table' || isUnifiedCableCanopy) ? cableColor : undefined,
            product.category === 'pendant' ? (isUnifiedCableCanopy ? cableColor : canopyColor) : undefined
        );
    };

    const handleAddReview = (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;
        addReview({
            productId: decodedId,
            userName: user.name,
            rating: reviewRating,
            comment: reviewComment,
            image: reviewImage || undefined
        });
        setReviewComment('');
        setReviewImage(null);
    };

    const materials = useMemo(() => {
        const allMaterials = [
            { id: 'guayubira' as const, name: 'Guayubira' },
            { id: 'roble' as const, name: 'Roble' },
            { id: 'palo-santo' as const, name: 'Palo Santo' },
        ];

        if (product?.name === 'Taini') {
            return allMaterials.filter(m => m.id !== 'palo-santo');
        }
        return allMaterials;
    }, [product]);

    const sizes = useMemo(() => {
        if (product?.variants && product.variants.some(v => !!v.size)) {
            // Get unique sizes from variants
            const uniqueSizes = Array.from(new Set(product.variants.map(v => v.size).filter(s => !!s)));
            // Map to the format needed for buttons. 
            // Try to map known codes to nice names, otherwise pass through
            const getName = (s: string) => {
                if (s === '1m') return '1 metro';
                if (s === '1.5m') return '1.5 metros';
                if (s === '2m') return '2 metros';
                return s;
            };
            return uniqueSizes.map(s => ({ id: s as string, name: getName(s as string) }));
        }

        return [
            { id: '1m', name: '1 metro' },
            { id: '1.5m', name: '1.5 metros' },
            { id: '2m', name: '2 metros' },
        ];
    }, [product]);

    const shadeTypes = [
        { id: 'lino' as const, name: 'Lino' },
        { id: 'blanco-calido' as const, name: 'Blanco Cálido' },
        { id: 'blanco-frio' as const, name: 'Blanco Frío' },
    ];

    const colors = [
        { id: 'blanco' as const, name: 'Blanco' },
        { id: 'negro' as const, name: 'Negro' },
    ];

    const getVariantStock = (material: string, size?: string) => {
        if (!product?.variants || product.variants.length === 0) return product?.stockCount ?? 0;
        const variant = product.variants.find(v => v.material === material && v.size === size);
        return variant ? variant.stock : 0;
    };

    const hasSizeVariants = useMemo(() => {
        return (product?.variants?.some(v => !!v.size)) || product?.id === 'new-1';
    }, [product]);

    const isSelectionInStock = () => {
        if (!product?.inStock) return false;
        if (!product?.variants || product.variants.length === 0) return product?.stockCount !== undefined && product.stockCount > 0;

        const sizeToCheck = hasSizeVariants ? selectedSize : undefined;
        return getVariantStock(selectedMaterial, sizeToCheck) > 0;
    };

    if (products.length === 0) {
        return (
            <div className="flex justify-center items-center min-h-[60vh]">
                <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
            </div>
        );
    }

    if (!product || product.isVisible === false) {
        notFound();
    }


    return (
        <div className="mx-auto max-w-7xl px-0 lg:px-8 py-4 lg:py-16">
            <Link
                href="/products"
                className="mb-6 px-4 lg:px-0 inline-flex items-center gap-2 text-sm font-medium text-stone-500 hover:text-primary"
            >
                <ArrowLeft size={16} /> Volver a la tienda
            </Link>

            <div className="grid grid-cols-1 gap-x-8 gap-y-8 lg:grid-cols-2">
                {/* Product Gallery */}
                <div className="space-y-4">
                    
                    {/* --- SWIPEABLE GALLERY (ALL DEVICES) --- */}
                    <div className="relative w-full aspect-square bg-stone-100 rounded-2xl overflow-hidden group">
                        <div 
                            className="flex w-full h-full overflow-x-auto snap-x snap-mandatory scroll-smooth hide-scrollbar cursor-grab active:cursor-grabbing" 
                            id="product-gallery"
                            onScroll={(e) => {
                                const scrollLeft = e.currentTarget.scrollLeft;
                                const width = e.currentTarget.offsetWidth;
                                setSelectedImageIndex(Math.round(scrollLeft / width));
                            }}
                        >
                            {product.images.map((img, idx) => (
                                <div key={idx} className="w-full h-full shrink-0 snap-center relative">
                                    <Image src={img} alt={`${product.name} ${idx + 1}`} fill className="object-cover" priority={idx === 0} sizes="(max-width: 1024px) 100vw, 50vw" />
                                </div>
                            ))}
                        </div>
                    </div>
                    
                    {/* Dots Indicator (Mobile mainly, but useful anywhere) */}
                    {product.images.length > 1 && (
                        <div className="flex justify-center gap-2 mt-3 mb-6 lg:hidden">
                            {product.images.map((_, idx) => (
                                <button 
                                    key={idx} 
                                    onClick={() => {
                                        const el = document.getElementById('product-gallery');
                                        if (el) el.scrollTo({ left: idx * el.offsetWidth, behavior: 'smooth' });
                                    }} 
                                    aria-label={`Ir a foto ${idx + 1}`}
                                    className={`h-2 rounded-full transition-all ${selectedImageIndex === idx ? 'w-6 bg-stone-800' : 'w-2 bg-stone-300'}`} 
                                />
                            ))}
                        </div>
                    )}

                    {/* Desktop Thumbnails */}
                    {product.images.length > 1 && (
                        <div className="hidden lg:grid grid-cols-4 gap-4 mt-4">
                            {product.images.map((image, index) => (
                                <button
                                    key={index}
                                    onClick={() => {
                                        const el = document.getElementById('product-gallery');
                                        if (el) el.scrollTo({ left: index * el.offsetWidth, behavior: 'smooth' });
                                    }}
                                    className={`relative aspect-square overflow-hidden rounded-xl bg-stone-100 transition-all ${selectedImageIndex === index ? 'ring-2 ring-stone-900 border-2 border-white opacity-100 shadow-md transform scale-105' : 'opacity-70 hover:opacity-100'}`}
                                >
                                    <Image
                                        src={image}
                                        alt={`${product.name} ${index + 1}`}
                                        fill
                                        className="object-cover"
                                        sizes="12vw"
                                    />
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                {/* Product Info */}
                <div className="flex flex-col px-4 lg:px-0">
                    <h1 className="text-3xl font-normal tracking-tight text-stone-900 sm:text-4xl">
                        {product.name}
                    </h1>

                    <div className="mt-4 flex items-center gap-4">
                        <p className="text-3xl font-normal text-stone-900">${product.price.toLocaleString()}</p>
                        {product.isComingSoon ? (
                            <span className="inline-flex items-center gap-1 rounded-full bg-[#5E6F5E] px-2.5 py-0.5 text-sm font-medium text-white shadow-sm">
                                <Clock size={14} /> Próximamente
                            </span>
                        ) : (!product.inStock || !(product.variants && product.variants.length > 0 ? product.variants.some(v => v.stock > 0) : (product.stockCount !== undefined && product.stockCount > 0))) ? (
                            <span className="inline-flex items-center rounded-full bg-red-50 px-2.5 py-0.5 text-sm font-medium text-red-700">
                                Agotado
                            </span>
                        ) : (
                            <span className="inline-flex items-center gap-1 rounded-full bg-green-50 px-2.5 py-0.5 text-sm font-medium text-green-700">
                                <Check size={14} /> En Stock
                            </span>
                        )}
                    </div>

                    <div className="mt-8 space-y-6">
                        <p className="text-base text-stone-600 leading-relaxed">
                            {product.description}
                        </p>

                        {/* Material Selector */}
                        <div>
                            <h3 className="text-sm font-medium text-stone-900 mb-3">Tipo de Madera</h3>
                            <div className={`grid gap-3 ${materials.length === 2 ? 'grid-cols-2' : 'grid-cols-3'}`}>
                                {materials.map((material) => {
                                    return (
                                        <button
                                            key={material.id}
                                            onClick={() => setSelectedMaterial(material.id)}
                                            className={`px-4 py-3 text-sm font-medium rounded-lg border-2 transition-colors
                                                ${selectedMaterial === material.id
                                                    ? 'border-primary bg-primary/5 text-primary'
                                                    : 'border-stone-200 text-stone-700 hover:border-stone-300'}
                                            `}
                                        >
                                            {material.name}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>

                        {/* Size Selector - Dynamic */}
                        {hasSizeVariants && (
                            <div>
                                <h3 className="text-sm font-medium text-stone-900 mb-3">Tamaño</h3>
                                <div className="grid grid-cols-3 gap-3">
                                    {sizes.map((size) => {
                                        const isAvailable = product.variants
                                            ? getVariantStock(selectedMaterial, size.id) > 0
                                            : true;
                                        return (
                                            <button
                                                key={size.id}
                                                // @ts-ignore
                                                onClick={() => setSelectedSize(size.id)}
                                                disabled={!isAvailable && !!product.variants}
                                                className={`px-4 py-3 text-sm font-medium rounded-lg border-2 transition-colors
                                                    ${selectedSize === size.id
                                                        ? 'border-primary bg-primary/5 text-primary'
                                                        : 'border-stone-200 text-stone-700 hover:border-stone-300'}
                                                    ${(!isAvailable && !!product.variants) ? 'opacity-50 cursor-not-allowed bg-stone-100 text-stone-400 border-stone-100' : ''}
                                                `}
                                            >
                                                {size.name}
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        )}

                        {/* Shade Type - Only for Table Lamps */}
                        {product.category === 'table' && (
                            <div>
                                <h3 className="text-sm font-medium text-stone-900 mb-3">Tipo de Pantalla</h3>
                                <div className="grid grid-cols-3 gap-3">
                                    {shadeTypes.map((shade) => (
                                        <button
                                            key={shade.id}
                                            onClick={() => setShadeType(shade.id)}
                                            className={`px-4 py-3 text-sm font-medium rounded-lg border-2 transition-colors ${shadeType === shade.id
                                                ? 'border-primary bg-primary/5 text-primary'
                                                : 'border-stone-200 text-stone-700 hover:border-stone-300'
                                                }`}
                                        >
                                            {shade.name}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Cable Color Selector */}
                        {(product.category === 'table' || (product.category === 'pendant' && product.id !== 'new-1' && product.id !== 'new-4')) && (
                            <div>
                                <h3 className="text-sm font-medium text-stone-900 mb-3">
                                    {product.category === 'pendant' ? 'Color Cable y Florón' : 'Color Cable'}
                                </h3>
                                <div className="grid grid-cols-2 gap-3">
                                    {colors.map((color) => (
                                        <button
                                            key={color.id}
                                            onClick={() => setCableColor(color.id)}
                                            className={`px-4 py-3 text-sm font-medium rounded-lg border-2 transition-colors ${cableColor === color.id
                                                ? 'border-primary bg-primary/5 text-primary'
                                                : 'border-stone-200 text-stone-700 hover:border-stone-300'
                                                }`}
                                        >
                                            {color.name}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Canopy Selector */}
                        {product.category === 'pendant' && (product.id === 'new-1' || product.id === 'new-4') && (
                            <div>
                                <h3 className="text-sm font-medium text-stone-900 mb-3">Color Florón</h3>
                                <div className="grid grid-cols-2 gap-3">
                                    {colors.map((color) => (
                                        <button
                                            key={color.id}
                                            onClick={() => setCanopyColor(color.id)}
                                            className={`px-4 py-3 text-sm font-medium rounded-lg border-2 transition-colors ${canopyColor === color.id
                                                ? 'border-primary bg-primary/5 text-primary'
                                                : 'border-stone-200 text-stone-700 hover:border-stone-300'
                                                }`}
                                        >
                                            {color.name}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        <div className="rounded-xl bg-stone-50 p-6 space-y-5 border border-stone-100 shadow-sm">
                            <div className="flex items-start gap-4">
                                <Hammer className="mt-0.5 h-6 w-6 text-[#5E6F5E]" />
                                <div>
                                    <p className="font-bold text-stone-900 text-sm">Hecho a mano en Argentina 🇦🇷</p>
                                    <p className="text-xs text-stone-500 mt-1">Cada lámpara es ensamblada y probada artesanalmente en Córdoba.</p>
                                </div>
                            </div>
                            <div className="flex items-start gap-4">
                                <Truck className="mt-0.5 h-6 w-6 text-[#5E6F5E]" />
                                <div>
                                    <p className="font-bold text-stone-900 text-sm">Envíos a todo el país</p>
                                    <p className="text-xs text-stone-500 mt-1">Gratis en pedidos superiores a $200.000.</p>
                                </div>
                            </div>
                            <div className="flex items-start gap-4">
                                <Shield className="mt-0.5 h-6 w-6 text-[#5E6F5E]" />
                                <div>
                                    <p className="font-bold text-stone-900 text-sm">1 Año de Garantía</p>
                                    <p className="text-xs text-stone-500 mt-1">Calidad estructural y eléctrica asegurada en tu compra.</p>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="mt-10 flex gap-4">
                        <Button
                            size="lg"
                            className="w-full flex-1 min-h-[56px] text-lg font-bold shadow-md hover:shadow-lg transition-all"
                            disabled={product.isComingSoon || !product.inStock || !isSelectionInStock()}
                            onClick={handleAddToCart}
                        >
                            {product.isComingSoon ? 'Próximamente' : (!product.inStock ? 'Sin Stock' : (isSelectionInStock() ? 'Añadir al Carrito' : 'Variante Agotada'))}
                        </Button>
                        <Button
                            variant="outline"
                            size="lg"
                            className="px-6 min-h-[56px] border-2 hover:border-red-500 hover:text-red-500 transition-colors"
                            onClick={() => toggleFavorite(product)}
                        >
                            <Heart
                                size={24}
                                className={isFavorite(product.id) ? 'fill-current text-red-500' : ''}
                            />
                        </Button>
                    </div>
                </div>
            </div>

            {/* Reviews Section */}
            <div className="mt-16 lg:mt-20 border-t border-stone-200 pt-16 px-4 lg:px-0">
                <h2 className="text-2xl font-normal text-stone-900 mb-8">Reseñas y Comentarios</h2>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                    {/* Review List */}
                    <div className="space-y-6">
                        {productReviews.length === 0 ? (
                            <div className="bg-stone-50 rounded-xl p-8 text-center">
                                <Star className="mx-auto h-12 w-12 text-stone-300 mb-4" />
                                <p className="text-stone-600">Aún no hay reseñas para este producto</p>
                            </div>
                        ) : (
                            productReviews.map(review => (
                                <div key={review.id} className="bg-white border border-stone-100 p-6 rounded-xl shadow-sm">
                                    <div className="flex justify-between items-start mb-4">
                                        <div>
                                            <p className="font-medium text-stone-900">{review.userName}</p>
                                            <p className="text-xs text-stone-400">{review.date}</p>
                                        </div>
                                        <div className="flex gap-0.5">
                                            {[...Array(5)].map((_, i) => (
                                                <Star key={i} size={14} className={i < review.rating ? "fill-yellow-400 text-yellow-400" : "text-stone-200"} />
                                            ))}
                                        </div>
                                    </div>
                                    <p className="text-stone-600 text-sm leading-relaxed">{review.comment}</p>
                                    {review.image && (
                                        <div className="mt-4 relative h-32 w-32 rounded-lg overflow-hidden border border-stone-200">
                                            <Image src={review.image} alt="User photo" fill className="object-cover" />
                                        </div>
                                    )}
                                </div>
                            ))
                        )}
                    </div>

                    {/* Add Review Form */}
                    <div className="bg-stone-50 p-8 rounded-2xl h-fit">
                        <h3 className="text-lg font-medium text-stone-900 mb-6">Deja tu opinión</h3>
                        {user ? (
                            <form onSubmit={handleAddReview} className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-stone-700 mb-2">Puntuación</label>
                                    <div className="flex gap-2">
                                        {[1, 2, 3, 4, 5].map((star) => (
                                            <button
                                                key={star}
                                                type="button"
                                                onClick={() => setReviewRating(star)}
                                                className="focus:outline-none"
                                            >
                                                <Star size={24} className={star <= reviewRating ? "fill-yellow-400 text-yellow-400" : "text-stone-300"} />
                                            </button>
                                        ))}
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-stone-700 mb-2">Tu comentario</label>
                                    <textarea
                                        required
                                        rows={4}
                                        className="w-full rounded-xl border border-stone-200 p-3 text-sm focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all"
                                        placeholder="Cuéntanos qué te pareció el producto..."
                                        value={reviewComment}
                                        onChange={(e) => setReviewComment(e.target.value)}
                                    />
                                </div>
                                <div className="pt-2">
                                    <label className="block text-sm font-medium text-stone-700 mb-2">Foto de tu lámpara (Opcional)</label>
                                    <div className="relative">
                                        {reviewImage ? (
                                            <div className="relative h-24 w-24 rounded-lg overflow-hidden border border-stone-200 mb-2">
                                                <Image src={reviewImage} alt="Preview" fill className="object-cover" />
                                                <button type="button" onClick={() => setReviewImage(null)} className="absolute top-1 right-1 bg-white/80 rounded-full p-1 text-red-500 hover:bg-white transition-colors">
                                                    <X size={14} />
                                                </button>
                                            </div>
                                        ) : (
                                            <input
                                                type="file"
                                                accept="image/*"
                                                className="w-full text-sm text-stone-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-primary/5 file:text-primary hover:file:bg-primary/10 cursor-pointer"
                                                disabled={isUploadingImage}
                                                onChange={async (e) => {
                                                    const file = e.target.files?.[0];
                                                    if (!file) return;
                                                    
                                                    setIsUploadingImage(true);
                                                    try {
                                                        const { createClient } = await import('@supabase/supabase-js');
                                                        const supabaseObj = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!);
                                                        const fileName = `review-${Date.now()}-${file.name.replace(/\s+/g, '-')}`;
                                                        const { data, error } = await supabaseObj.storage.from('products').upload(fileName, file);
                                                        
                                                        if (data) {
                                                            const { data: { publicUrl } } = supabaseObj.storage.from('products').getPublicUrl(fileName);
                                                            setReviewImage(publicUrl);
                                                        } else {
                                                            alert('Error al subir la foto');
                                                        }
                                                    } catch (err) {
                                                        alert('Hubo un problema procesando tu foto');
                                                    } finally {
                                                        setIsUploadingImage(false);
                                                    }
                                                }}
                                            />
                                        )}
                                        {isUploadingImage && <p className="text-xs text-primary mt-2 animate-pulse">Subiendo foto...</p>}
                                    </div>
                                </div>
                                <Button type="submit" className="w-full" disabled={isUploadingImage}>
                                    {isUploadingImage ? 'Procesando...' : 'Publicar Reseña'}
                                </Button>
                            </form>
                        ) : (
                            <div className="text-center py-6">
                                <p className="text-stone-600 text-sm mb-4">Debes iniciar sesión para dejar una reseña.</p>
                                <Link href="/login">
                                    <Button variant="outline" size="sm">Iniciar Sesión</Button>
                                </Link>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Similar Products */}
            {similarProducts.length > 0 && (
                <div className="mt-20 border-t border-stone-200 pt-16 px-4 lg:px-0 mb-10">
                    <div className="grid grid-cols-1 gap-12 lg:grid-cols-12 lg:gap-16 items-start">
                        <div className="lg:col-span-8 w-full">
                            <div className="flex overflow-x-auto snap-x snap-mandatory gap-4 pb-6 sm:grid sm:grid-cols-3 sm:gap-6 sm:pb-0 [&::-webkit-scrollbar]:hidden [-ms-overflow-style:none] [scrollbar-width:none]">
                                {similarProducts.map((similarProduct) => (
                                    <Link key={similarProduct.id} href={`/products/${similarProduct.id}`} className="group block min-w-[70vw] sm:min-w-0 snap-center shrink-0">
