'use client';

import * as React from 'react';
import { Search, X, ArrowRight } from 'lucide-react';
import { useApp } from '@/context/AppContext';
import Link from 'next/link';
import Image from 'next/image';
import { useRouter } from 'next/navigation';


interface SearchModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export function SearchModal({ isOpen, onClose }: SearchModalProps) {
    const { products } = useApp();
    const [query, setQuery] = React.useState('');
    const router = useRouter();
    const inputRef = React.useRef<HTMLInputElement>(null);

    React.useEffect(() => {
        if (isOpen) {
            setTimeout(() => inputRef.current?.focus(), 100);
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'unset';
        }
        return () => {
            document.body.style.overflow = 'unset';
        };
    }, [isOpen]);

    const normalizeString = (str: string) => {
        return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();
    };

    const searchStr = normalizeString(query);

    const filteredProducts = query
        ? products.filter((product) =>
            normalizeString(product.name).includes(searchStr) ||
            normalizeString(product.description).includes(searchStr)
        )
        : [];


    const handleLinkClick = (id: string) => {
        onClose();
        router.push(`/products/${id}`);
    }

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[60] flex items-start justify-center pt-20">
            {/* Backdrop */}
            <div
                className="fixed inset-0 bg-black/40 backdrop-blur-sm transition-opacity"
                onClick={onClose}
            />

            {/* Modal */}
            <div className="relative w-full max-w-2xl transform overflow-hidden rounded-xl bg-white shadow-2xl transition-all">
                <div className="relative border-b border-stone-200">
                    <Search className="absolute left-4 top-4 h-6 w-6 text-stone-400" />
                    <input
                        ref={inputRef}
                        type="text"
                        className="w-full border-none bg-transparent py-4 pl-14 pr-12 text-lg text-stone-900 placeholder:text-stone-400 focus:outline-none focus:ring-0"
                        placeholder="Buscar lámparas..."
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                    />
                    <button
                        onClick={onClose}
                        className="absolute right-4 top-4 rounded-full p-1 text-stone-400 hover:bg-stone-100 hover:text-stone-500"
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Results */}
                {query && (
                    <div className="max-h-[60vh] overflow-y-auto p-4">
                        {filteredProducts.length === 0 ? (
                            <div className="py-8 text-center text-stone-500">
                                No encontramos productos para "{query}"
                            </div>
                        ) : (
                            <div className="grid gap-4">
                                {filteredProducts.map((product) => (
                                    <button
                                        key={product.id}
                                        onClick={() => handleLinkClick(product.id)}
                                        className="flex items-center gap-4 rounded-lg p-2 text-left transition-colors hover:bg-stone-50"
                                    >
                                        <div className="relative h-16 w-16 shrink-0 overflow-hidden rounded-md border border-stone-200">
                                            <Image
                                                src={product.images[0]}
                                                alt={product.name}
                                                fill
                                                className="object-cover"
                                            />
                                        </div>
                                        <div className="flex-1">
                                            <h3 className="font-medium text-stone-900">{product.name}</h3>
                                            <p className="text-sm text-stone-500 line-clamp-1">{product.description}</p>
                                        </div>
                                        <div className="text-sm font-semibold text-stone-900">
                                            ${product.price}
                                        </div>
                                        <ArrowRight className="h-4 w-4 text-stone-400" />
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                {!query && (
                    <div className="p-4 text-center text-sm text-stone-400">
                        Escribe para buscar...
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Product, products as initialProducts } from '@/lib/products';
import { supabase } from '@/lib/supabase';

export interface Order {
    id: string;
    customer: string;
    email: string;
    date: string;
    total: number;
    status: 'Pedido recibido' | 'Pago acreditado' | 'En preparación' | 'Embalado' | 'Despachado' | 'Entregado' | 'Devolución' | 'Cancelado';
    items: number;
    shippingMethod: 'shipping' | 'pickup';
    paymentMethod: 'card' | 'transfer';
    address?: string;
    city?: string;
    province?: string;
    postalCode?: string;
    phone?: string;
    items_details?: any[];
    created_at?: string;
    details?: {
        name: string;
        price: number;
        quantity: number;
        material?: string;
        size?: string;
        shade?: string;
        cable?: string;
        canopy?: string;
    }[];
}

export interface Query {
    id: number;
    name: string;
    email: string;
    subject: string;
    message: string;
    date: string;
    read: boolean;
    replied?: boolean;
    created_at?: string;
}

export interface Review {
    id: string;
    productId: string;
    userName: string;
    rating: number;
    comment: string;
    image?: string;
    date: string;
    created_at?: string;
}

interface AppContextType {
    products: Product[];
    orders: Order[];
    queries: Query[];
    reviews: Review[];
    addProduct: (product: Omit<Product, 'id'>) => void;
    updateProduct: (id: string, product: Partial<Product>) => Promise<{ error: any }>;
    deleteProduct: (id: string) => void;
    updateOrderStatus: (id: string, status: Order['status']) => void;
    addQuery: (query: Omit<Query, 'id' | 'date' | 'read'>) => void;
    markQueryAsRead: (id: number) => void;
    replyToQuery: (id: number, response: string) => void;
    subscribeToNewsletter: (email: string) => void;
    addReview: (review: Omit<Review, 'id' | 'date'>) => void;
    addOrder: (order: Omit<Order, 'date' | 'status'> | Omit<Order, 'id' | 'date' | 'status'> & { id?: string }) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export function AppProvider({ children }: { children: ReactNode }) {
    const [products, setProducts] = useState<Product[]>([]);
    const [orders, setOrders] = useState<Order[]>([]);
    const [queries, setQueries] = useState<Query[]>([]);
    const [reviews, setReviews] = useState<Review[]>([]);
    const [subscribers, setSubscribers] = useState<string[]>([]);

    useEffect(() => {
        const loadInitialData = async () => {
            const mappedInitial = initialProducts.map(p => ({ ...p, isVisible: true, stockCount: p.stockCount || 0 }));
            if (supabase) {
                try {
                    // Helper para parsear fechas
                    const parseDate = (dateStr: string) => {
                        if (!dateStr) return 0;
                        const months: Record<string, number> = { 'ene': 0, 'feb': 1, 'mar': 2, 'abr': 3, 'may': 4, 'jun': 5, 'jul': 6, 'ago': 7, 'sep': 8, 'oct': 9, 'nov': 10, 'dic': 11 };
                        const parts = dateStr.toLowerCase().split(' ').filter(p => p !== 'de' && p !== 'del' && p !== '');
                        if (parts.length >= 3) {
                            const day = parseInt(parts[0], 10);
                            const monthStr = parts[1].replace('.', '').substring(0, 3);
                            const year = parseInt(parts[2], 10);
                            if (!isNaN(day) && !isNaN(year) && typeof months[monthStr] !== 'undefined') {
                                return new Date(year, months[monthStr], day).getTime();
                            }
                        }
                        const ts = Date.parse(dateStr);
                        return isNaN(ts) ? 0 : ts;
                    };

                    const sortOrders = (ordersList: any[]) => {
                        return [...ordersList].sort((a, b) => {
                            let timeA = 0; let timeB = 0;
                            if (a.created_at) timeA = new Date(a.created_at).getTime();
                            if (b.created_at) timeB = new Date(b.created_at).getTime();
                            if (timeA === 0 && a.id && a.id.startsWith('ORD-') && a.id.length > 10) {
                                const ts = parseInt(a.id.replace('ORD-', ''), 10);
                                if (!isNaN(ts) && ts > 1000000000) timeA = ts;
                            }
                            if (timeB === 0 && b.id && b.id.startsWith('ORD-') && b.id.length > 10) {
                                const ts = parseInt(b.id.replace('ORD-', ''), 10);
                                if (!isNaN(ts) && ts > 1000000000) timeB = ts;
                            }
                            if (timeA === 0) timeA = parseDate(a.date);
                            if (timeB === 0) timeB = parseDate(b.date);
                            if (timeA === timeB) return b.id.localeCompare(a.id);
                            return timeB - timeA;
                        });
                    };

                    // Cargar productos y reviews (públicos)
                    try {
                        const { data: pData, error: pErr } = await supabase.from('products').select('*');
                        if (pErr) console.error("SUPABASE PRODUCTS ERROR:", pErr);

                        if (pData && pData.length > 0) {
                            setProducts(pData);
                        } else {
                            setProducts(mappedInitial);
                        }

                        const { data: rData } = await supabase.from('reviews').select('*');
                        if (rData) setReviews(rData);
                    } catch (e) {
                         setProducts(mappedInitial);
                    }

                    // Intentar cargar datos sensibles mediante API administrativa
                    // Si falla silenciosamente (401), es un usuario normal.
                    try {
                        const adminRes = await fetch('/api/admin/data');
                        if (adminRes.ok) {
                            const adminData = await adminRes.json();
                            if (adminData.orders) setOrders(sortOrders(adminData.orders));
                            if (adminData.queries) setQueries(adminData.queries);
                            if (adminData.subscribers) setSubscribers(adminData.subscribers);
                        }
                    } catch (e) {
                        // Silent fail
                    }

                } catch (err) {
                    console.error("Critical Admin Load error:", err);
                    setProducts(mappedInitial);
                }
            } else {
                setProducts(mappedInitial);
            }
        };
        loadInitialData();
    }, []);

    const addProduct = async (p: any) => {
        const newP = { ...p, id: Math.random().toString(36).substr(2, 9) };
        setProducts(prev => [newP, ...prev]);
        if (supabase) await supabase.from('products').insert(newP);
    };

    const updateProduct = async (id: string, fields: any) => {
        setProducts(prev => prev.map(p => p.id === id ? { ...p, ...fields } : p));
        if (supabase) {
            const { error } = await supabase.from('products').update(fields).eq('id', id);
            return { error };
        }
        return { error: null };
    };

    const deleteProduct = async (id: string) => {
        setProducts(prev => prev.filter(p => p.id !== id));
        if (supabase) await supabase.from('products').delete().eq('id', id);
    };

    return (
        <AppContext.Provider value={{
            products, orders, queries, reviews,
            addProduct, updateProduct, deleteProduct,
            updateOrderStatus: (id, status) => {
                setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
                fetch('/api/admin/data', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ table: 'orders', action: 'update', data: { status }, match: { id } })
                }).catch(console.error);
            },
            addReview: async (review) => {
                const tempId = Math.random().toString(36).substr(2, 9);
                const newR = { ...review, id: tempId, date: new Date().toLocaleDateString() };
                setReviews(prev => [newR as any, ...prev]);
                if (supabase) {
                    const { id, ...dbReview } = newR;
                    const { data, error } = await supabase.from('reviews').insert(dbReview).select().single();
                    if (error) {
                        console.error("Review Insert Error:", error);
                    } else if (data) {
                        setReviews(prev => prev.map(r => r.id === tempId ? data : r));
                    }
                }
            },
            addOrder: (order) => {
                const newO = { ...order, date: new Date().toLocaleDateString(), status: 'Pedido recibido' };
                setOrders(prev => [newO as any, ...prev]);
                if (supabase) supabase.from('orders').insert(newO).then();
            },
            addQuery: async (q) => {
                const newQ = { ...q, date: new Date().toLocaleDateString(), read: false };
                // Add an optimistic ID for UI so we don't need to select it back 
                // (RLS blocks selecting queries for security)
                setQueries(prev => [{ ...newQ, id: crypto.randomUUID() } as any, ...prev]);
                if (supabase) {
                    const { error } = await supabase.from('queries').insert(newQ);
                    if (error) console.error("Error inserting query:", error);
                }
            },
            markQueryAsRead: (id) => {
                setQueries(prev => prev.map(q => q.id === id ? { ...q, read: true } : q));
                fetch('/api/admin/data', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ table: 'queries', action: 'update', data: { read: true }, match: { id } })
                }).catch(console.error);
            },
            replyToQuery: (id) => {
                setQueries(prev => prev.map(q => q.id === id ? { ...q, replied: true } : q));
                fetch('/api/admin/data', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ table: 'queries', action: 'update', data: { replied: true }, match: { id } })
                }).catch(console.error);
            },
            subscribeToNewsletter: async (email) => {
                if (supabase) {
                    supabase.from('subscribers').insert({ email }).then();
                }
                try {
                    await fetch('/api/newsletter', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ email })
                    });
                } catch (error) {
                    console.error("Error calling newsletter API", error);
                }
            }
        }}>
            {children}
        </AppContext.Provider>
    );
}

export const useApp = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useApp missing');
    return context;
};

'use client';

import { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { supabase } from '@/lib/supabase';

export interface User {
    id: string;
    email: string;
    name: string;
}

interface AuthContextType {
    user: User | null;
    login: (email: string, password: string) => Promise<void>;
    register: (name: string, email: string, password: string) => Promise<void>;
    logout: () => void;
    isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
    const [user, setUser] = useState<User | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    const syncUser = async (supabaseUser: any) => {
        if (!supabaseUser) return null;
        try {
            const { data: profile } = await supabase!.from('users').select('*').eq('id', supabaseUser.id).single();
            const name = profile?.full_name || profile?.name || supabaseUser.user_metadata?.name || 'Usuario';
            return { id: supabaseUser.id, email: supabaseUser.email || '', name };
        } catch (e) {
            // Fallback to auth data if profile fetch fails
            return { id: supabaseUser.id, email: supabaseUser.email || '', name: supabaseUser.user_metadata?.name || 'Usuario' };
        }
    };

    useEffect(() => {
        const checkSession = async () => {
            if (!supabase) {
                setIsLoading(false);
                return;
            }
            const { data: { session } } = await supabase.auth.getSession();
            if (session?.user) {
                const u = await syncUser(session.user);
                if (u) setUser(u);
            }
            setIsLoading(false);
        };
        checkSession();

        if (supabase) {
            const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
                if ((event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED') && session?.user) {
                    const u = await syncUser(session.user);
                    if (u) setUser(u);
                } else if (event === 'SIGNED_OUT') {
                    setUser(null);
                }
            });
            return () => subscription.unsubscribe();
        }
    }, []);

    const login = async (email: string, password: string) => {
        setIsLoading(true);
        if (!supabase) throw new Error('Error de conexión');
        try {
            const { data, error } = await supabase.auth.signInWithPassword({
                email: email.trim().toLowerCase(),
                password
            });
            if (error) throw new Error('Email o contraseña incorrectos');
            if (data.user) {
                const u = await syncUser(data.user);
                if (u) setUser(u);
            }
        } finally {
            setIsLoading(false);
        }
    };

    const register = async (name: string, email: string, password: string) => {
        setIsLoading(true);
        if (!supabase) throw new Error('Error de conexión');
        const cleanEmail = email.trim().toLowerCase();
        try {
            const { data, error } = await supabase.auth.signUp({
                email: cleanEmail,
                password,
                options: { data: { name } }
            });
            if (error) throw new Error(error.message);
            if (data.user) {
                // Upsert to ensure user exists in public.users
                await supabase.from('users').upsert({
                    id: data.user.id,
                    full_name: name,
                    email: cleanEmail,
                }, { onConflict: 'id' });
                setUser({ id: data.user.id, name, email: cleanEmail });
            }
        } finally {
            setIsLoading(false);
        }
    };

    const logout = async () => {
        if (supabase) await supabase.auth.signOut();
        setUser(null);
    };

    return (
        <AuthContext.Provider value={{ user, login, register, logout, isLoading }}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (context === undefined) throw new Error('useAuth missing');
    return context;
}

